		function buscar_legajo()
{
  if(Ctrl('buscar_legajo').GetXValue()=="") return;

  Ctrl('buscar_nro_leg').SetXValue("");

  var xmlParam = new NomadXML('PARAM');
  var TXT_FIND = Ctrl('buscar_legajo').GetXValue();
	xmlParam.SetAttr('TXT_FIND', TXT_FIND);
  FilterGrid(xmlParam.ToString());
}


function buscar_nro_leg()
{
	if(Ctrl('buscar_nro_leg').GetXValue()<0) Ctrl('buscar_nro_leg').SetXValue("");
	if(Ctrl('buscar_nro_leg').GetXValue()=="") return;

	Ctrl('buscar_legajo').SetXValue("");

  var xmlParam = new NomadXML('PARAM');
  var NRO_LEG = Number(Ctrl('buscar_nro_leg').GetXValue());		
	xmlParam.SetAttr('NRO_LEG', NRO_LEG);
	FilterGrid(xmlParam.ToString());	
}



