function GetPageByID(ID)
{
	var listPERS = Ctrl("listPERS");

	for (var i=0; i<listPERS.IDs.length; i++)
	{		
		if (listPERS.IDs[i]==ID)
			return Math.floor(i/listPERS.PageSize);
	}
}




function ExpandEstr(id)
{	
	myTree = Ctrl("TREE_CONT_POLICY_TREE");		
	myEstr = myTree.GetGroup(id);					
	if(myEstr != null && !myEstr.isExpanded)
	{
		LoadChilds(myTree, myEstr);
		myTree.ExpandGroup(myEstr,true);
	}
}





function LoadChilds(objTree, objEstr)
{	     
	var XMLResult;
	var NodeID;


	//////////////////////////////////////////////////////////////////////////////////////////
	//Ejecuto el Query
	if(objEstr != null && objEstr.FullId.split("/").length > 1)	
	{
		NodeID=objEstr.FullId;
		XMLResult=nSQL.GetXML(Ctrl("main").getResource("qry:estructuras"), '<DATO seg="./JER/'+NodeID.substr(8)+'" c_estr_padre="'+objEstr.Id+'" />');
	} else           
	{
		NodeID='ORG:SEG';
		XMLResult=nSQL.GetXML(Ctrl("main").getResource("qry:estructuras"), '<DATO seg="./JER" c_estr_padre="" />');
	}        

	//////////////////////////////////////////////////////////////////////////////////////////
	//Actualizo los Campos
	for (cur=XMLResult.FirstChild(); cur!=null; cur=cur.Next())
	{         
		if (cur.FindElement("access")==null)
		{
			cur.SetAttr("imgClose","../check/lock_check_n.gif");
			cur.SetAttr("imgOpen" ,"../check/lock_check_n.gif");
			cur.SetAttr("tag", cur.GetAttr("tag")+"|0");
		} 
		else
		{
			cur.SetAttr("imgClose","../../../../NomadFile.aspx?mode=GRAPHICS&report=NucleusRH.Base.Seguridad.IconEstr.rpt&color="+cur.GetAttr("color"));
			cur.SetAttr("imgOpen" ,"../../../../NomadFile.aspx?mode=GRAPHICS&report=NucleusRH.Base.Seguridad.IconEstr.rpt&color="+cur.GetAttr("color"));
			cur.SetAttr("tag", cur.GetAttr("tag")+"|1");
		}
	}               

	//////////////////////////////////////////////////////////////////////////////////////////
	//Actualizo el ARBOL
	objTree.SetXML(NodeID, XMLResult.ToString());		
	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());	
}

function OnLoad()
{    	
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	//Cargo el Arbol de Seguridad	
	var GROUP_TREE=clsClientTree("CONT_POLICY_TREE","POLICY_TREE_VALUE","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,RefreshData);
	GROUP_TREE.SetXML(null, nSQL.Get(Ctrl("main").getResource("qry:org-seg"), ""));

	//Actualizo los Botones	              
	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());	
	RefreshData(); 
	RefreshAplica();
}

function RefreshData()
{			
	myTree = Ctrl("TREE_CONT_POLICY_TREE");	
	myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());	

  var lst=Ctrl("listPERS");
  var lstg=Ctrl("listGROUPS");
  lst.IDs=new Array();
  lstg.IDs=new Array();

	if (myEstr==null || myEstr.Id=="ORG:SEG")
	{ 
		lst.MsgEmply="No hay ningún nodo selecionado."; 
		lstg.MsgEmply="No hay ningún nodo selecionado.";
	} else                            
	if (myEstr.Tag.split("|")[2]=="0")
	{
 		lst.MsgEmply="No se disponen de suficientes{br}privilegios para visualizar{br}el contenido del Nodo."; 
 		lstg.MsgEmply="No se disponen de suficientes{br}privilegios para visualizar{br}el contenido del Nodo.";
	} else
	{
		var id = myEstr.Tag.split("|")[0];		
		var np, nSQL;

		np = GetProxy();
		nSQL = np.SQLService(); 	

		var qry = Ctrl("main").getResource("qry:per");	     
	  var result = nSQL.GetXML(qry, "<DATO oi_estructura =\""+id+"\"/>");

	  //Genero la Lista de IDS de Personas
	  for (var cur=result.FirstChild(); cur!=null; cur=cur.Next())
	    lst.IDs.push(cur.GetAttr("id"));

	  lst.MsgEmply="No hay Personas Asignadas";

	  var qry = Ctrl("main").getResource("qry:gru");	     
	  var result = nSQL.GetXML(qry, "<DATO oi_estructura =\""+id+"\"/>");  

	  //Genero la Lista de IDS de Grupos
	  for (var cur=result.FirstChild(); cur!=null; cur=cur.Next())
	    lstg.IDs.push(cur.GetAttr("id"));

	  lstg.MsgEmply="No hay Grupos Asignados";

 	}
 	Ctrl("arrcheck").DelAllRow();
 	Ctrl("arrcheckg").DelAllRow();
  lst.ResetSQL();
  lstg.ResetSQL();	  

 	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());
}

function RefreshArray()
{
	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());
}
function RefreshButtons(groupid)
{				
	var estr_add = true;
	var estr_cut = true;
	var estr_paste = true;
	var estr_del = true;
	var per_add = true;
	var per_mark = true;
	var per_del = true;
	var gru_add = true;
	var gru_mark = true;
	var gru_del = true;

	if (groupid=="")
	{
		estr_add = false;
		estr_cut = false;
		estr_paste = false;
		estr_del = false;
		per_add = false;
		per_mark = false;
		per_del = false;
		gru_add = false;
		gru_mark = false;
		gru_del = false;
	}  else           
	{		            
		myTree = Ctrl("TREE_CONT_POLICY_TREE");			
		myEstr = myTree.GetGroup(groupid);
		if (myEstr==null || myEstr.Tag.split("|")[2]=="0")
		{
			estr_add = false;
			estr_cut = false;
			estr_paste = false;
			estr_del = false;
			per_add = false;
			per_mark = false;
			per_del = false;
			gru_add = false;
			gru_mark = false;
			gru_del = false;
		} else
		{
			pathList=groupid.toString().split("/");		
			if (pathList.length==1)
			{
				estr_add = true;
				estr_cut = false;
				if(Ctrl('ESTR_CUT_ID').GetXValue() == "")
					estr_paste = false;
				estr_del = false;
				per_add = false;
				per_mark = false;
				per_del = false;
				gru_add = false;
				gru_mark = false;
				gru_del = false;
			} 
			else		
			{
				estr_add = true;
				estr_cut = true;			
				estr_del = false;
				per_add = true;
				per_mark = true;
				per_del = false;
				estr_paste = true;
				gru_add = true;
				gru_mark = true;
				gru_del = false;

				if(Ctrl('ESTR_CUT_ID').GetXValue() == "") estr_paste = false;
				if(Ctrl("arrcheck").CountRow() > 0) per_del = true;
				if(Ctrl("arrcheckg").CountRow() > 0) gru_del = true;
				if(myEstr.Tag.split("|")[1] == "1" && Ctrl("l_seguridad").GetXValue() == 1) estr_del = true;

				//No permitir pegar sobre el mismo nodo
				if(Ctrl('ESTR_CUT_ID').GetXValue()==groupid) estr_paste = false;

				//No permitir pegar en nodo hijo
				if(groupid.toString().split("/").length > Ctrl('ESTR_CUT_ID').GetXValue().toString().split("/").length) estr_paste = false;

			}
		}		
	}              

	CtrlEnabled("ESTR_ADD"     					  , estr_add);
	CtrlEnabled("ESTR_CUT"      				  , estr_cut);
	CtrlEnabled("ESTR_PASTE"    				  , estr_paste);	
	CtrlEnabled("ESTR_DELETE"    					, estr_del);
	CtrlEnabled("listPERS_PER_ADD"        , per_add);
	CtrlEnabled("listPERS_PER_MARK"       , per_mark);
	CtrlEnabled("listPERS_PER_DELETE"     , per_del);   
	CtrlEnabled("listGROUPS_GRU_ADD"      , gru_add);
	CtrlEnabled("listGROUPS_GRU_MARK"     , gru_mark);
	CtrlEnabled("listGROUPS_GRU_DELETE"   , gru_del);
}

function ESTR_ADD(myCTRL)
{
	var parent, id, list;

	list=Ctrl('POLICY_TREE_VALUE').GetXValue().split("/");
	parent = list[0];

	if(list.length > 1) 
	{
		id = list[list.length-1];		

		myTree = Ctrl("TREE_CONT_POLICY_TREE");
		myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());		
		myEstr.Tag = myEstr.Tag.split("|")[0]+"|0|"+myEstr.Tag.split("|")[2];		
	}
	else
		id = "";

	if(parent == 'ORG:SEG')
		parent = '1';
	openNewFlow("NucleusRH.Base.Seguridad.Organigramas.ESTRUCTURA.MAIN.STD.flow","ADD","<ID c_estr_padre=\""+id+"\" PARENT=\""+parent+"\" />",new ObjectResult(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");
}

function ESTR_DELETE(myCTRL)
{		
	var id, list, myTree, myEstr;

	myTree = Ctrl("TREE_CONT_POLICY_TREE");
	myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());
	id = myEstr.Tag.split("|")[0];	

	list=Ctrl('POLICY_TREE_VALUE').GetXValue().split("/");	
	list.length--;	
	list.length--;	
	list = list.join("/");	

	openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","DELESTR","<ID ID=\""+id+"\" />",new ObjectResult(list),"L");
}

function ESTR_CUT(myCTRL)
{
	myTree = Ctrl("TREE_CONT_POLICY_TREE");
	myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());

	list=Ctrl('POLICY_TREE_VALUE').GetXValue().split("/");
	list.length--;	
	list = list.join("/");

	myEstr.ImgOp = "../Images/Tree/estructura_d.ico";
	myEstr.ImgCl = "../Images/Tree/estructura_d.ico";	
	myTree.Draw(list);

	RefreshTree();	
	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());

	Ctrl("ESTR_CUT_ID").SetXValue(Ctrl('POLICY_TREE_VALUE').GetXValue());
}

function ESTR_PASTE(myCTRL)
{	
	var code, parent, id, list;

	list=Ctrl('POLICY_TREE_VALUE').GetXValue().split("/");
	if(list.length <= 1)
		padre = "";
	else
		padre = list[list.length - 1];


	myEstr = myTree.GetGroup(Ctrl('ESTR_CUT_ID').GetXValue());
	list = Ctrl('ESTR_CUT_ID').GetXValue().split("/"); 
	code = list[list.length - 1];
	id = myEstr.Tag.split("|")[0];	
	aplicaseg = Ctrl("l_seguridad").GetXValue();

	openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","PASTEESTR","<ID PARENT=\""+ padre + "\" CODE=\""+ code + "\" ID=\""+id+"\" aplicaseg=\""+ aplicaseg + "\"/>",new ObjectResultPaste(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");	
}	

function ObjectResult(ramaacargar)
{        	
	this.id = ramaacargar; 
	this.processResult= function(xmlin)
	{				
		RefreshTree();				
		ReloadTree(this.id);		
		RefreshData();		
		RefreshButtons(ramaacargar);		
	}
}

function ObjectResultPaste(ramaacargar)
{        	
	rama=Ctrl('ESTR_CUT_ID').GetXValue().split("/");	
	rama.length--;	
	rama=rama.join("/");

	this.id = ramaacargar; 
	this.processResult= function(xmlin)
	{		
		RefreshTree();
		ReloadTree(rama);	
		ReloadTree(this.id);		
		RefreshData();
		RefreshButtons(ramaacargar);
	}
}

function ReloadTree(id)
{	
	myTree = Ctrl("TREE_CONT_POLICY_TREE");		
	myEstr = myTree.GetGroup(id);				
	LoadChilds(myTree, myEstr);	
	if(myEstr != null)
		myTree.ExpandGroup(myEstr,true);

}  

function RefreshTree()
{
	if(Ctrl("ESTR_CUT_ID").GetXValue() != "")
	{		
		myEstrCut = myTree.GetGroup(Ctrl('ESTR_CUT_ID').GetXValue());	

		listCut=Ctrl('ESTR_CUT_ID').GetXValue().split("/");
		listCut.length--;	
		listCut = listCut.join("/");

		myEstrCut.ImgOp = "../../../NomadFile.aspx?mode=GRAPHICS&amp;report=NucleusRH.Base.Seguridad.IconEstr.rpt&amp;color="+myEstrCut.Tag.split("|")[2];
		myEstrCut.ImgCl = "../../../NomadFile.aspx?mode=GRAPHICS&amp;report=NucleusRH.Base.Seguridad.IconEstr.rpt&amp;color="+myEstrCut.Tag.split("|")[2];		
		myTree.Draw(listCut);

		Ctrl("ESTR_CUT_ID").SetXValue("");
	}
}

function PER_ADD()
{
	myTree = Ctrl("TREE_CONT_POLICY_TREE");
	myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());
	id = myEstr.Tag.split("|")[0];	
	aplicaseg = Ctrl("l_seguridad").GetXValue();

  openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","ADDPER","<ID ID=\""+id+"\" aplicaseg=\""+ aplicaseg + "\"/>",new ObjectResult(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");
}   

function PER_MARK()
{	
	if(Ctrl("arrcheck").CountRow() == 0)
	{		
		//Genero la Lista de IDS
	  var lst=Ctrl("listPERS");

	  var ids = lst.IDs;

	  for (var X=0; X<ids.length; X++)	    
	    Ctrl("arrcheck").AddRow().SetAttr("ID",ids[X]);

	  lst.ResetSQL();
	}
	else
	{
		Ctrl("listPERS").SetXValue("");
	 	Ctrl("arrcheck").DelAllRow();
		RefreshData();
		RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());		
	}
}

function PER_DELETE()
{               
	var xmlparam = new NomadXML("<DATO><ROWS/></DATO>");
	myTree = Ctrl("TREE_CONT_POLICY_TREE");
	myEstr = myTree.GetGroup(Ctrl('POLICY_TREE_VALUE').GetXValue());
	id = myEstr.Tag.split("|")[0];	

	xmlparam.SetAttr("oi_estructura", id);

	values=""; sep="";
	for (t=0,n=0; t<Ctrl("arrcheck").CountRow(); t++, n++)
	{		
		if (n>=50)
		{              
			xmlparam.FirstChild().AddTailElement("VALUES").SetAttr("IDS", values);
			values=""; sep=""; n=0;
		}                  
		values+=sep+Ctrl("arrcheck").GetRow(t).GetAttr("ID");
		sep=",";
	}
	if (values!="") 
		xmlparam.FirstChild().AddTailElement("VALUES").SetAttr("IDS", values)

	if(Ctrl("l_seguridad").GetXValue() == false)
	{                                                                   
	 	openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","DELPERSS",xmlparam.ToString(),new ObjectResult(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");	
	}
	else
	{                 
		openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","DELPER",xmlparam.ToString(),new ObjectResult(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");
  }
} 

