function Aplica()
{    
	var xmlparam = new NomadXML("<DATO><ROWS/></DATO>");         
	CtrlEnabled("APLICA", false);
	CtrlEnabled("NOAPLICA", true);  
	Ctrl("l_seguridad").SetXValue(1);                 

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();	
	var org;  

	org = nSQL.GetOBJ(Ctrl("main").getResource("qry:organigrama"), "");  
	if(org.id != "")
	{
		 openNewFlow("NucleusRH.Base.Seguridad.Organigramas.flow","APLICASEG","<ID ID=\""+org.id+"\" />",new ObjectResult(Ctrl('POLICY_TREE_VALUE').GetXValue()),"L");
	} 

	RefreshButtons(Ctrl('POLICY_TREE_VALUE').GetXValue());	  
}       

